export enum VoiceClassification {
  AI_GENERATED = 'AI-Generated',
  HUMAN_GENERATED = 'Human-Generated'
}

export interface DetectionResult {
  classification: VoiceClassification;
  confidenceScore: number;
  explanation: string;
  detectedLanguage: string;
  artifacts: string[];
  spectralAnomalies: string[];
}

export type SupportedLanguage = 'Tamil' | 'English' | 'Hindi' | 'Malayalam' | 'Telugu' | 'Auto-Detect';

export interface AppState {
  isProcessing: boolean;
  result: DetectionResult | null;
  error: string | null;
  selectedLanguage: SupportedLanguage;
}

import { GoogleGenAI, Type } from "@google/genai";
import { DetectionResult, VoiceClassification, SupportedLanguage } from "../types";

const MODEL_NAME = 'gemini-3-flash-preview';

export async function analyzeAudio(
  base64Audio: string,
  mimeType: string,
  targetLanguage: SupportedLanguage
): Promise<DetectionResult> {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  const systemInstruction = `
    You are a world-class audio forensic expert specialized in detecting synthetic voice vs. authentic human speech.
    Your task is to analyze the provided audio for markers of AI generation (TTS, voice cloning, deepfakes).

    Look for:
    1. Spectral anomalies: Lack of natural noise, robotic frequency cutoff, or "perfect" harmonics.
    2. Prosody & Cadence: Unnatural breathing patterns (or complete lack thereof), metallic timber, or uncanny rhythmic perfection.
    3. Linguistic context in the following languages: Tamil, English, Hindi, Malayalam, and Telugu.

    If targetLanguage is 'Auto-Detect', identify the language first.
    Return the result strictly as JSON.
  `;

  const prompt = `Analyze this audio sample. The expected or primary language is ${targetLanguage}. Determine if it is AI-generated or human-generated. Provide a confidence score (0-100) and a detailed technical explanation.`;

  try {
    const response = await ai.models.generateContent({
      model: MODEL_NAME,
      contents: {
        parts: [
          { inlineData: { data: base64Audio, mimeType } },
          { text: prompt }
        ]
      },
      config: {
        systemInstruction,
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            classification: {
              type: Type.STRING,
              description: "Must be exactly 'AI-Generated' or 'Human-Generated'",
            },
            confidenceScore: {
              type: Type.NUMBER,
              description: "Confidence percentage from 0 to 100",
            },
            explanation: {
              type: Type.STRING,
              description: "Detailed forensic explanation",
            },
            detectedLanguage: {
              type: Type.STRING,
              description: "The language detected in the audio",
            },
            artifacts: {
              type: Type.ARRAY,
              items: { type: Type.STRING },
              description: "Specific synthetic markers found",
            },
            spectralAnomalies: {
              type: Type.ARRAY,
              items: { type: Type.STRING },
              description: "Technical frequency/waveform issues",
            }
          },
          required: ["classification", "confidenceScore", "explanation", "detectedLanguage", "artifacts", "spectralAnomalies"]
        }
      }
    });

    const result = JSON.parse(response.text || '{}');
    return result as DetectionResult;
  } catch (error) {
    console.error("Gemini Analysis Error:", error);
    throw new Error("Failed to analyze audio sample. Please check the file format and try again.");
  }
}

