const App: React.FC = () => {
  const [state, setState] = useState<AppState>({
    isProcessing: false,
    result: null,
    error: null,
    selectedLanguage: 'Auto-Detect'
  });

  const [isRecording, setIsRecording] = useState(false);
  const [audioUrl, setAudioUrl] = useState<string | null>(null);
  const [base64Data, setBase64Data] = useState<string | null>(null);
  const [mimeType, setMimeType] = useState<string>('audio/mp3');

  const mediaRecorderRef = useRef<MediaRecorder | null>(null);
  const audioChunksRef = useRef<Blob[]>([]);

  const fileInputRef = useRef<HTMLInputElement>(null);

  const blobToBase64 = (blob: Blob): Promise<string> => {
    return new Promise((resolve, reject) => {
      const reader = new FileReader();
      reader.readAsDataURL(blob);
      reader.onload = () => {
        const base64String = (reader.result as string).split(',')[1];
        resolve(base64String);
      };
      reader.onerror = (error) => reject(error);
    });
  };

  const handleFileUpload = async (event: React.ChangeEvent<HTMLInputElement>) => {
    const file = event.target.files?.[0];
    if (!file) return;

    if (!file.type.startsWith('audio/')) {
      setState(prev => ({ ...prev, error: "Please upload a valid audio file (MP3, WAV, etc.)" }));
      return;
    }

    try {
      const base64 = await blobToBase64(file);
      setBase64Data(base64);
      setMimeType(file.type);
      setAudioUrl(URL.createObjectURL(file));
      setState(prev => ({ ...prev, error: null, result: null }));
    } catch (err) {
      setState(prev => ({ ...prev, error: "Error reading audio file" }));
    }
  };

  const startRecording = async () => {
    try {
      const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
      const mediaRecorder = new MediaRecorder(stream);
      mediaRecorderRef.current = mediaRecorder;
      audioChunksRef.current = [];

      mediaRecorder.ondataavailable = (event) => {
        if (event.data.size > 0) audioChunksRef.current.push(event.data);
      };

      mediaRecorder.onstop = async () => {
        const audioBlob = new Blob(audioChunksRef.current, { type: 'audio/webm' });
        const base64 = await blobToBase64(audioBlob);
        setBase64Data(base64);
        setMimeType('audio/webm');
        setAudioUrl(URL.createObjectURL(audioBlob));
      };

      mediaRecorder.start();
      setIsRecording(true);
      setState(prev => ({ ...prev, error: null, result: null }));
    } catch (err) {
      setState(prev => ({ ...prev, error: "Microphone access denied or not available." }));
    }
  };

  const stopRecording = () => {
    if (mediaRecorderRef.current && isRecording) {
      mediaRecorderRef.current.stop();
      setIsRecording(false);
      mediaRecorderRef.current.stream.getTracks().forEach(track => track.stop());
    }
  };

  const handleRunAnalysis = async () => {
    if (!base64Data) return;

    setState(prev => ({ ...prev, isProcessing: true, error: null }));
    try {
      const result = await analyzeAudio(base64Data, mimeType, state.selectedLanguage);
      setState(prev => ({ ...prev, result, isProcessing: false }));
